import React, { useState } from 'react';
import { uid, grade } from './db';
import { toast } from './ui.jsx';

const LOGO_SRC = process.env.PUBLIC_URL + '/logo.png';

const CO_ACTIVITIES = [
  'General Knowledge','Art Education','Health & Physical Education',
  'Scientific Skills','Thinking Skills','Moral Education','Yoga / P.T.','Sports',
];
const DISCIPLINE_ITEMS = [
  'Regularity & Punctuality','Sincerity','Behavior & Values',
  'Respectfulness for Rules & Regulations','Attitude Towards Teachers',
  'Attitude Towards School-Mates','Attitude Towards Society','Attitude Towards Nation',
];
const GRADES_8 = ['A1','A2','B1','B2','C1','C2','D','E'];

function grade8(pct) {
  if (pct >= 91) return 'A1';
  if (pct >= 81) return 'A2';
  if (pct >= 71) return 'B1';
  if (pct >= 61) return 'B2';
  if (pct >= 51) return 'C1';
  if (pct >= 41) return 'C2';
  if (pct >= 33) return 'D';
  return 'E';
}

function gradeColor(g) {
  return {A1:'#166534',A2:'#065f46',B1:'#1e40af',B2:'#1d4ed8',C1:'#92400e',C2:'#b45309',D:'#c2410c',E:'#991b1b'}[g]||'#374151';
}
function gradeBg(g) {
  return {A1:'#dcfce7',A2:'#d1fae5',B1:'#dbeafe',B2:'#eff6ff',C1:'#fef3c7',C2:'#fffbeb',D:'#ffedd5',E:'#fee2e2'}[g]||'#f3f4f6';
}

export default function ReportCardStudio({ db, logo }) {
  const classes = db.classes.map(c => c.name);
  const [rcCls, setRcCls] = useState('');
  const [selStu, setSelStu] = useState('all');

  // Per-student overrides: { [sid]: { addr, attP, attT, coGrades:{act:g}, discGrades:{item:g} } }
  const [overrides, setOverrides] = useState({});
  const [activeTab, setActiveTab] = useState('info'); // 'info' | 'co' | 'disc' | 'att'

  const clsStudents = rcCls ? db.students.filter(s => s.cls === rcCls) : [];
  const editStu = selStu !== 'all' ? db.students.find(s => s.id === selStu) : null;

  const getOvr = (sid) => overrides[sid] || {};
  const setOvr = (sid, patch) => setOverrides(o => ({ ...o, [sid]: { ...(o[sid]||{}), ...patch } }));
  const setCoGrade = (sid, act, g) => setOvr(sid, { coGrades: { ...(getOvr(sid).coGrades||{}), [act]: g } });
  const setDiscGrade = (sid, item, g) => setOvr(sid, { discGrades: { ...(getOvr(sid).discGrades||{}), [item]: g } });

  // Compute attendance from db.att
  const getAtt = (sid) => {
    let p = 0, t = 0;
    Object.values(db.att).forEach(d => { if (d[sid] !== undefined) { t++; if (d[sid]==='P'||d[sid]==='L') p++; } });
    return { p, t };
  };

  // Exams
  const clsExams = db.exams.filter(e => !e.cls || e.cls === rcCls);
  const t1Exams  = clsExams.filter(e => e.term === 'Term1');
  const t2Exams  = clsExams.filter(e => e.term === 'Term2');
  const subjects = rcCls ? ((db.classes.find(c=>c.name===rcCls)?.subs||'').split(',').map(s=>s.trim()).filter(Boolean)) : [];

  const getMark = (examId, sid) => {
    const key = examId + '_' + rcCls;
    const v = (db.marks[key]||{})[sid];
    return v !== undefined ? v : null;
  };
  const getSubjectExams = (su, termExams) => termExams.filter(e => e.su === su);
  const findComp = (exams, kws) => { const e = exams.find(ex => kws.some(k => ex.name.toLowerCase().includes(k))); return e || null; };

  // Auto-compute co/disc grades from subject marks
  const autoGrades = (sid) => {
    let totalPct = 0, count = 0;
    subjects.forEach(su => {
      const t1 = getSubjectExams(su, t1Exams);
      const t2 = getSubjectExams(su, t2Exams);
      const t1T = t1.length===1 ? getMark(t1[0].id,sid) : null;
      const t2T = t2.length===1 ? getMark(t2[0].id,sid) : null;
      const t1M = t1.reduce((a,e)=>a+(e.max||0),0)||100;
      const t2M = t2.reduce((a,e)=>a+(e.max||0),0)||100;
      const t1H = t1T!==null ? Math.round(t1T/t1M*50) : null;
      const t2H = t2T!==null ? Math.round(t2T/t2M*50) : null;
      if (t1H!==null && t2H!==null) { totalPct += t1H+t2H; count++; }
    });
    const avg = count > 0 ? Math.round(totalPct/count) : 50;
    const g = grade8(avg);
    const coG = {}; CO_ACTIVITIES.forEach(a => { coG[a] = g; });
    const dG  = {}; DISCIPLINE_ITEMS.forEach(d => { dG[d] = g; });
    return { coGrades: coG, discGrades: dG };
  };

  const applyAutoGrades = (sid) => {
    const ag = autoGrades(sid);
    setOvr(sid, ag);
    toast('Grades auto-filled from marks');
  };

  const applyAutoGradesAll = () => {
    clsStudents.forEach(s => {
      const ag = autoGrades(s.id);
      setOverrides(o => ({ ...o, [s.id]: { ...(o[s.id]||{}), ...ag } }));
    });
    toast('Auto-filled grades for all students');
  };

  // ── Generate report card HTML ──────────────────────────────────
  const genRC = (studentsToGen) => {
    if (!rcCls) { toast('Select a class first', 'err'); return; }
    if (!studentsToGen.length) { toast('No students', 'err'); return; }
    const school = db.settings.school || 'LORD KRISHNA PUBLIC SCHOOL';
    const yr     = db.settings.year   || '2025-2026';
    const addr   = db.settings.addr   || '';
    const prin   = db.settings.prin   || '';
    const phone  = db.settings.phone  || '';

    const css = `
      @import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800;900&display=swap');
      *{box-sizing:border-box;margin:0;padding:0}
      body{font-family:'Inter',Arial,sans-serif;background:#f1f5f9;-webkit-print-color-adjust:exact;print-color-adjust:exact}
      .page{width:210mm;min-height:297mm;margin:0 auto 24px;background:#fff;box-shadow:0 2px 24px rgba(0,0,0,0.10);position:relative;overflow:hidden;page-break-after:always}
      /* left accent */
      .page::before{content:'';position:absolute;left:0;top:0;bottom:0;width:5px;background:linear-gradient(180deg,#3b82f6,#0ea5e9)}
      /* logo watermark */
      .wm{position:absolute;top:50%;left:50%;transform:translate(-50%,-50%);width:260px;height:260px;opacity:0.04;pointer-events:none;z-index:0;object-fit:contain}
      /* header */
      .hdr{background:linear-gradient(135deg,#eff6ff 0%,#dbeafe 60%,#e0f2fe 100%);padding:18px 26px 14px 30px;display:flex;align-items:center;gap:16px;border-bottom:2px solid #bfdbfe;position:relative}
      .hdr-logo{width:56px;height:56px;border-radius:50%;border:2px solid #93c5fd;overflow:hidden;flex-shrink:0;background:#fff;display:flex;align-items:center;justify-content:center}
      .hdr-logo img{width:100%;height:100%;object-fit:contain}
      .hdr-logo-fb{font-size:22px;font-weight:900;color:#1e40af;font-family:serif}
      .hdr-text{flex:1;text-align:center}
      .hdr-school{font-size:18px;font-weight:900;color:#1e3a8a;letter-spacing:1px;text-transform:uppercase}
      .hdr-addr{font-size:9.5px;color:#3b82f6;margin-top:2px}
      .hdr-title{display:inline-block;margin-top:8px;background:#dbeafe;border:1px solid #93c5fd;border-radius:20px;padding:3px 16px;font-size:11.5px;font-weight:800;color:#1e40af;letter-spacing:0.8px;text-transform:uppercase}
      .hdr-badge{flex-shrink:0;text-align:center}
      .hdr-cls-box{background:#fff;border:1.5px solid #93c5fd;border-radius:10px;padding:5px 14px;text-align:center}
      .hdr-cls-lbl{font-size:8.5px;color:#3b82f6;text-transform:uppercase;letter-spacing:0.8px;font-weight:700}
      .hdr-cls-val{font-size:17px;font-weight:900;color:#1e3a8a;line-height:1.1}
      .hdr-yr{font-size:9.5px;color:#64748b;margin-top:5px}
      /* info strip */
      .info{background:#f8faff;border-bottom:1.5px solid #e2e8f0;padding:10px 26px 10px 30px;display:grid;grid-template-columns:1fr 1fr;gap:0 36px}
      .ir{display:flex;align-items:baseline;padding:3px 0;border-bottom:1px dashed #e2e8f0}
      .ir:last-child{border-bottom:none}
      .il{font-size:10px;font-weight:700;color:#3b82f6;min-width:110px;flex-shrink:0}
      .iv{font-size:11px;color:#1e293b;font-weight:500}
      /* marks table */
      .tw{padding-left:5px}
      .mt{width:100%;border-collapse:collapse;font-size:10px}
      .mt th,.mt td{border:1px solid #bfdbfe;text-align:center;padding:4.5px 2px;line-height:1.2}
      .th-a{background:#dbeafe;color:#1e3a8a;font-weight:800;font-size:10.5px;text-align:left;padding-left:8px}
      .th-t{background:#eff6ff;color:#1e40af;font-weight:800;font-size:11px;border-bottom:2px solid #93c5fd}
      .th-o{background:#e0f2fe;color:#0369a1;font-weight:800;font-size:10.5px;border-bottom:2px solid #7dd3fc}
      .th-s{background:#f8faff;color:#475569;font-weight:700;font-size:9px}
      .th-m{background:#fdf2f8;color:#9d174d;font-weight:800;font-size:9.5px}
      .td-s{text-align:left;padding-left:8px;font-weight:700;color:#1e40af;background:#f0f6ff;font-size:10.5px}
      .td-tot{background:#eff6ff;font-weight:800;color:#1e40af}
      .td-g{background:#f0fdf4;font-weight:900;color:#166534;font-size:11px}
      .td-r{font-weight:700;color:#7c3aed;font-size:10px}
      tr:nth-child(even) td:not(.td-s):not(.td-tot):not(.td-g){background:#f8faff}
      .gb{border-radius:3px;padding:1px 4px;font-weight:900;font-size:9.5px}
      /* grading note */
      .gn{background:#f8faff;border-top:1px solid #e2e8f0;border-bottom:1px solid #e2e8f0;padding:5px 26px 5px 30px;font-size:8.5px;color:#64748b;font-style:italic;line-height:1.5}
      /* totals */
      .tb{background:linear-gradient(90deg,#f0f6ff,#e0f2fe);border-bottom:1px solid #bfdbfe;padding:8px 26px 8px 30px;display:flex;align-items:center;gap:20px}
      .ti{display:flex;align-items:center;gap:8px}
      .tl{font-size:10.5px;font-weight:700;color:#1e40af}
      .tv{background:#fff;border:1.5px solid #93c5fd;border-radius:7px;padding:3px 13px;font-size:12.5px;font-weight:900;color:#1e3a8a}
      .pb{flex:1;margin-left:8px}
      .pb-bg{height:7px;background:#dbeafe;border-radius:4px;overflow:hidden}
      .pb-fill{height:100%;border-radius:4px}
      .pb-lbl{font-size:8.5px;color:#94a3b8;margin-top:2px;text-align:right}
      /* co-scholastic */
      .cw{display:grid;grid-template-columns:1fr 1fr;border-bottom:1px solid #e2e8f0}
      .ch:first-child{border-right:1px solid #e2e8f0}
      .ct{width:100%;border-collapse:collapse;font-size:10px}
      .ct .chm{background:#eff6ff;color:#1e40af;font-weight:800;font-size:10.5px;padding:5px 8px;text-align:center;border-bottom:1.5px solid #bfdbfe}
      .ct .chs{background:#f8faff;color:#475569;font-weight:700;font-size:9px;padding:3px 6px;border:1px solid #e2e8f0;text-align:center}
      .ct td{border:1px solid #e2e8f0;padding:3.5px 6px}
      .ca{text-align:left;color:#1e293b;font-size:10px}
      .cg{text-align:center;font-weight:800;font-size:10px}
      /* footer */
      .ft{padding:8px 26px 12px 30px}
      .ft-top{display:flex;justify-content:space-between;align-items:center;margin-bottom:5px}
      .att-b{display:inline-flex;align-items:center;gap:5px;background:#eff6ff;border:1px solid #bfdbfe;border-radius:5px;padding:3px 10px;font-weight:700;color:#1e40af;font-size:10.5px}
      .rm-b{display:inline-flex;align-items:center;gap:5px;border-radius:5px;padding:3px 10px;font-weight:700;font-size:10.5px}
      .rm-g{background:#f0fdf4;color:#166534;border:1px solid #bbf7d0}
      .rm-o{background:#fffbeb;color:#92400e;border:1px solid #fde68a}
      .rm-r{background:#fef2f2;color:#991b1b;border:1px solid #fecaca}
      .promo{font-size:10.5px;color:#475569;margin-bottom:8px;font-style:italic}
      .sr{display:flex;justify-content:space-between;padding-top:12px;border-top:1px solid #e5e7eb;margin-top:4px}
      .si{text-align:center;min-width:100px}
      .sl{border-top:1.5px solid #374151;margin-top:26px;padding-top:3px;font-size:9.5px;color:#374151;font-weight:600}
      @media print{@page{size:A4;margin:5mm}body{background:#fff}.page{box-shadow:none;margin:0;page-break-after:always}}
    `;

    const perfColor = pct => pct>=75?'#22c55e':pct>=50?'#f59e0b':'#ef4444';

    const w = window.open('', '_blank');
    let html = `<!DOCTYPE html><html><head><meta charset="utf-8"><title>Report Cards — ${rcCls}</title><style>${css}</style></head><body>`;

    studentsToGen.forEach(s => {
      const ovr = overrides[s.id] || {};
      const dbAtt = getAtt(s.id);
      const attP = ovr.attP !== undefined ? ovr.attP : dbAtt.p;
      const attT = ovr.attT !== undefined ? ovr.attT : dbAtt.t;

      const subjectRows = subjects.map(su => {
        const t1 = getSubjectExams(su, t1Exams);
        const t2 = getSubjectExams(su, t2Exams);
        const fc = (exams, kws) => { const e = exams.find(ex => kws.some(k=>ex.name.toLowerCase().includes(k))); return e ? getMark(e.id,s.id) : null; };
        const t1_pt=fc(t1,['per.test','periodic','per test','pt']);
        const t1_nb=fc(t1,['note','notebook','note book']);
        const t1_sea=fc(t1,['sea','sub enrich','enrichment']);
        const t1_hy=fc(t1,['half','half yearly','hy']);
        const t1Total=t1.length===1?getMark(t1[0].id,s.id):(t1_pt!==null||t1_nb!==null||t1_sea!==null||t1_hy!==null)?(t1_pt||0)+(t1_nb||0)+(t1_sea||0)+(t1_hy||0):null;
        const t2_pt=fc(t2,['per.test','periodic','per test','pt']);
        const t2_nb=fc(t2,['note','notebook','note book']);
        const t2_sea=fc(t2,['sea','sub enrich','enrichment']);
        const t2_ye=fc(t2,['yearly','annual','year exam','ye']);
        const t2Total=t2.length===1?getMark(t2[0].id,s.id):(t2_pt!==null||t2_nb!==null||t2_sea!==null||t2_ye!==null)?(t2_pt||0)+(t2_nb||0)+(t2_sea||0)+(t2_ye||0):null;
        const t1Max=t1.reduce((a,e)=>a+(e.max||0),0)||100;
        const t2Max=t2.reduce((a,e)=>a+(e.max||0),0)||100;
        const t1Half=t1Total!==null?Math.round(t1Total/t1Max*50):null;
        const t2Half=t2Total!==null?Math.round(t2Total/t2Max*50):null;
        const grand=(t1Half!==null&&t2Half!==null)?t1Half+t2Half:null;
        return {su,t1_pt,t1_nb,t1_sea,t1_hy,t1Total,t2_pt,t2_nb,t2_sea,t2_ye,t2Total,grand};
      });

      const validRows=subjectRows.filter(r=>r.grand!==null);
      const overallTotal=validRows.reduce((a,r)=>a+(r.grand||0),0);
      const overallMax=validRows.length*100;
      const overallPct=overallMax>0?Math.round(overallTotal/overallMax*100):0;

      // Rank
      const classScores=clsStudents.map(st=>subjects.reduce((sum,su)=>{
        const t1=getSubjectExams(su,t1Exams),t2=getSubjectExams(su,t2Exams);
        const t1T=t1.length===1?getMark(t1[0].id,st.id):null,t2T=t2.length===1?getMark(t2[0].id,st.id):null;
        const t1M=t1.reduce((a,e)=>a+(e.max||0),0)||100,t2M=t2.reduce((a,e)=>a+(e.max||0),0)||100;
        return sum+(t1T!==null?Math.round(t1T/t1M*50):0)+(t2T!==null?Math.round(t2T/t2M*50):0);
      },0)).sort((a,b)=>b-a);
      const rank=classScores.indexOf(overallTotal)+1;

      const fmt=v=>v!==null&&v!==undefined?v:'—';
      const gBadge=(g)=>g!=='—'?`<span class="gb" style="color:${gradeColor(g)};background:${gradeBg(g)}">${g}</span>`:'—';

      const subRows=subjectRows.map(r=>{
        const g=r.grand!==null?grade8(r.grand):'—';
        return `<tr>
          <td class="td-s">${r.su}</td>
          <td>${fmt(r.t1_pt)}</td><td>${fmt(r.t1_nb)}</td><td>${fmt(r.t1_sea)}</td><td>${fmt(r.t1_hy)}</td>
          <td class="td-tot">${fmt(r.t1Total)}</td>
          <td>${fmt(r.t2_pt)}</td><td>${fmt(r.t2_nb)}</td><td>${fmt(r.t2_sea)}</td><td>${fmt(r.t2_ye)}</td>
          <td class="td-tot">${fmt(r.t2Total)}</td>
          <td class="td-g">${fmt(r.grand)}</td>
          <td style="font-size:10px">${gBadge(g)}</td>
          <td class="td-r">${rank>0&&r.grand!==null?rank:'—'}</td>
        </tr>`;
      }).join('');

      const coG=ovr.coGrades||{};
      const dG=ovr.discGrades||{};
      const coRows=CO_ACTIVITIES.map(a=>{const g=coG[a]||'A2';return`<tr><td class="ca">${a}</td><td class="cg" style="color:${gradeColor(g)}">${g}</td><td class="cg" style="color:${gradeColor(g)}">${g}</td></tr>`;}).join('');
      const discRows=DISCIPLINE_ITEMS.map(d=>{const g=dG[d]||'A2';return`<tr><td class="ca" style="font-size:9.5px">${d}</td><td class="cg" style="color:${gradeColor(g)}">${g}</td><td class="cg" style="color:${gradeColor(g)}">${g}</td></tr>`;}).join('');

      const remarkCls=overallPct>=75?'rm-g':overallPct>=50?'rm-o':'rm-r';
      const remarkText=overallPct>=75?'Good!':overallPct>=50?'Satisfactory':'Needs Improvement';
      const barColor=perfColor(overallPct);
      const logoTag=logo?`<img src="${logo}" class="wm" alt=""/>`:'';

      html+=`
      <div class="page">
        ${logoTag}
        <div class="hdr">
          <div class="hdr-logo">${logo?`<img src="${logo}" alt=""/>`:`<span class="hdr-logo-fb">${school.charAt(0)}</span>`}</div>
          <div class="hdr-text">
            <div class="hdr-school">${school}</div>
            <div class="hdr-addr">${addr}${phone?' | Ph: '+phone:''}</div>
            <div class="hdr-title">Report Card</div>
          </div>
          <div class="hdr-badge">
            <div class="hdr-cls-box"><div class="hdr-cls-lbl">Class</div><div class="hdr-cls-val">${rcCls}</div></div>
            <div class="hdr-yr">Session: ${yr}</div>
          </div>
        </div>
        <div class="info">
          <div>
            <div class="ir"><span class="il">Student's Name</span><span class="iv">${s.fn} ${s.ln}</span></div>
            <div class="ir"><span class="il">Father's Name</span><span class="iv">${s.father||'—'}</span></div>
            <div class="ir"><span class="il">Mother's Name</span><span class="iv">${s.mother||'—'}</span></div>
            <div class="ir"><span class="il">Date of Birth</span><span class="iv">${s.dob||'—'}</span></div>
            <div class="ir"><span class="il">Address</span><span class="iv">${ovr.addr||s.addr||addr||'—'}</span></div>
          </div>
          <div>
            <div class="ir"><span class="il">Roll No.</span><span class="iv">${s.roll||'—'}</span></div>
            <div class="ir"><span class="il">Admission No.</span><span class="iv">${s.admNo||'—'}</span></div>
            <div class="ir"><span class="il">Gender</span><span class="iv">${s.gn||'—'}</span></div>
            <div class="ir"><span class="il">Blood Group</span><span class="iv">${s.blood||'—'}</span></div>
          </div>
        </div>
        <div class="tw">
          <table class="mt">
            <thead>
              <tr>
                <th rowspan="3" class="th-a" style="width:82px">Scholastic<br/>Area</th>
                <th colspan="5" class="th-t">Term 1 &nbsp;(100 Marks)</th>
                <th colspan="5" class="th-t">Term 2 &nbsp;(100 Marks)</th>
                <th colspan="3" class="th-o">Overall</th>
              </tr>
              <tr>
                <th colspan="5" class="th-s" style="font-size:8px;color:#94a3b8">Per.Test + Notebook + SEA + Half Yearly</th>
                <th colspan="5" class="th-s" style="font-size:8px;color:#94a3b8">Per.Test + Notebook + SEA + Yearly Exam</th>
                <th colspan="3" class="th-s">T1(50) + T2(50)</th>
              </tr>
              <tr class="th-s">
                <th>Per.<br/>Test</th><th>Note<br/>Book</th><th>SEA</th><th>Half<br/>Yearly</th><th>Total</th>
                <th>Per.<br/>Test</th><th>Note<br/>Book</th><th>SEA</th><th>Yearly<br/>Exam</th><th>Total</th>
                <th>Grand<br/>Total</th><th>Grade</th><th>Rank</th>
              </tr>
              <tr class="th-m">
                <td class="td-s" style="font-size:9.5px">Subjects</td>
                <td>10</td><td>5</td><td>5</td><td>80</td><td>100</td>
                <td>10</td><td>5</td><td>5</td><td>80</td><td>100</td>
                <td>100</td><td></td><td></td>
              </tr>
            </thead>
            <tbody>${subRows||'<tr><td colspan="14" style="text-align:center;padding:10px;color:#94a3b8;font-style:italic">No marks entered</td></tr>'}</tbody>
          </table>
        </div>
        <div class="gn"><strong>8-Point Scale:</strong> A1(91-100%) A2(81-90%) B1(71-80%) B2(61-70%) C1(51-60%) C2(41-50%) D(33-40%) E(≤32%) &nbsp;<strong>*SEA</strong>=Sub Enrichment Activity</div>
        <div class="tb">
          <div class="ti"><span class="tl">Overall Marks</span><span class="tv">${overallTotal} / ${overallMax}</span></div>
          <div class="ti"><span class="tl">Percentage</span><span class="tv">${overallPct}%</span></div>
          <div class="pb"><div class="pb-bg"><div class="pb-fill" style="width:${overallPct}%;background:${barColor}"></div></div><div class="pb-lbl">${overallPct}% — ${remarkText}</div></div>
        </div>
        <div class="cw">
          <div class="ch">
            <table class="ct">
              <thead><tr><td colspan="3" class="chm">Co-Scholastic Areas</td></tr><tr><th class="chs" style="text-align:left;padding-left:8px">Activity</th><th class="chs">T1</th><th class="chs">T2</th></tr></thead>
              <tbody>${coRows}</tbody>
            </table>
          </div>
          <div class="ch">
            <table class="ct">
              <thead><tr><td colspan="3" class="chm">Discipline</td></tr><tr><th class="chs" style="text-align:left;padding-left:8px">Element</th><th class="chs">T1</th><th class="chs">T2</th></tr></thead>
              <tbody>${discRows}</tbody>
            </table>
          </div>
        </div>
        <div class="ft">
          <div class="ft-top">
            <span class="att-b">Attendance : ${attP} / ${attT} days</span>
            <span class="rm-b ${remarkCls}">Remarks : ${remarkText}</span>
          </div>
          <div class="promo">${overallPct>=33?`Congratulations! Promoted to Class ${rcCls}.`:'Result: Detained — Please contact the school.'}</div>
          <div class="sr">
            <div class="si"><div class="sl">Date : ${new Date().toLocaleDateString('en-IN')}</div></div>
            <div class="si"><div class="sl">Class Teacher</div></div>
            <div class="si"><div class="sl">Principal${prin?' ('+prin+')':''}</div></div>
            <div class="si"><div class="sl">Parent / Guardian</div></div>
          </div>
        </div>
      </div>`;
    });

    html += `<script>window.onload=()=>window.print()<\/script></body></html>`;
    w.document.write(html);
    w.document.close();
    toast('Report cards generated');
  };

  const GradeSelect = ({ value, onChange }) => (
    <select value={value||'A2'} onChange={e=>onChange(e.target.value)}
      style={{fontSize:11,fontWeight:700,padding:'2px 4px',borderRadius:5,border:'1px solid #bfdbfe',
        background:gradeBg(value||'A2'),color:gradeColor(value||'A2'),cursor:'pointer',outline:'none'}}>
      {GRADES_8.map(g=><option key={g} value={g}>{g}</option>)}
    </select>
  );

  return (
    <div className="space-y-6">
      {/* Class + Student selector */}
      <div className="bg-white rounded-2xl p-6 shadow-sm border border-blue-100">
        <p className="text-xs font-bold uppercase tracking-widest text-blue-400 mb-4">Configuration</p>
        <div className="flex flex-wrap gap-4 items-end">
          <div>
            <label className="block text-xs font-bold text-slate-500 mb-1.5 uppercase tracking-wider">Class</label>
            <select value={rcCls} onChange={e=>{setRcCls(e.target.value);setSelStu('all');}}
              className="p-2.5 bg-blue-50 border border-blue-200 rounded-xl text-sm text-slate-700 min-w-[140px] focus:ring-2 focus:ring-blue-300 outline-none">
              <option value="">Select Class</option>
              {classes.map(c=><option key={c}>{c}</option>)}
            </select>
          </div>
          {rcCls && (
            <div>
              <label className="block text-xs font-bold text-slate-500 mb-1.5 uppercase tracking-wider">Edit Student</label>
              <select value={selStu} onChange={e=>setSelStu(e.target.value)}
                className="p-2.5 bg-blue-50 border border-blue-200 rounded-xl text-sm text-slate-700 min-w-[180px] focus:ring-2 focus:ring-blue-300 outline-none">
                <option value="all">— All Students —</option>
                {clsStudents.map(s=><option key={s.id} value={s.id}>{s.fn} {s.ln}</option>)}
              </select>
            </div>
          )}
          {rcCls && selStu !== 'all' && (
            <button onClick={()=>applyAutoGrades(selStu)}
              className="px-4 py-2.5 bg-blue-50 border border-blue-200 text-blue-700 rounded-xl text-xs font-bold hover:bg-blue-100 transition-colors">
              Auto-fill from Marks
            </button>
          )}
          {rcCls && (
            <button onClick={applyAutoGradesAll}
              className="px-4 py-2.5 bg-indigo-50 border border-indigo-200 text-indigo-700 rounded-xl text-xs font-bold hover:bg-indigo-100 transition-colors">
              Auto-fill All Students
            </button>
          )}
        </div>
      </div>

      {/* Per-student editor */}
      {rcCls && selStu !== 'all' && editStu && (
        <div className="bg-white rounded-2xl shadow-sm border border-blue-100 overflow-hidden">
          {/* Sub-tabs */}
          <div className="flex border-b border-blue-100 bg-blue-50">
            {[['info','person','Student Info'],['co','star','Co-Scholastic'],['disc','verified','Discipline'],['att','calendar_today','Attendance']].map(([id,icon,label])=>(
              <button key={id} onClick={()=>setActiveTab(id)}
                className={`flex items-center gap-1.5 px-5 py-3 text-xs font-bold transition-all border-0 cursor-pointer ${activeTab===id?'bg-white text-blue-700 border-b-2 border-blue-500':'text-slate-500 hover:text-slate-700 bg-transparent'}`}>
                <span className="material-symbols-outlined text-sm">{icon}</span>{label}
              </button>
            ))}
          </div>

          <div className="p-6">
            {/* INFO TAB */}
            {activeTab==='info' && (
              <div className="grid grid-cols-2 gap-4">
                {[
                  ['Address Override','addr','text',editStu.addr||''],
                  ['Admission No.','admNo','text',editStu.admNo||''],
                ].map(([label,key,type,placeholder])=>(
                  <div key={key}>
                    <label className="block text-xs font-bold text-slate-500 mb-1.5 uppercase tracking-wider">{label}</label>
                    <input type={type} placeholder={placeholder||label}
                      value={(overrides[selStu]||{})[key]||''}
                      onChange={e=>setOvr(selStu,{[key]:e.target.value})}
                      className="w-full p-2.5 bg-blue-50 border border-blue-200 rounded-xl text-sm text-slate-700 focus:ring-2 focus:ring-blue-300 outline-none"/>
                  </div>
                ))}
                <div className="col-span-2 text-xs text-slate-400 italic">Other student info (name, father, DOB, roll, etc.) is pulled from the Students directory.</div>
              </div>
            )}

            {/* CO-SCHOLASTIC TAB */}
            {activeTab==='co' && (
              <div>
                <p className="text-xs text-slate-400 mb-4 italic">Set T1 and T2 grades for each co-scholastic activity. Both terms use the same grade.</p>
                <div className="grid grid-cols-2 gap-3">
                  {CO_ACTIVITIES.map(act=>{
                    const g=(overrides[selStu]?.coGrades||{})[act]||'A2';
                    return (
                      <div key={act} className="flex items-center justify-between bg-blue-50 rounded-xl px-4 py-2.5 border border-blue-100">
                        <span className="text-sm text-slate-700 font-medium">{act}</span>
                        <GradeSelect value={g} onChange={v=>setCoGrade(selStu,act,v)}/>
                      </div>
                    );
                  })}
                </div>
              </div>
            )}

            {/* DISCIPLINE TAB */}
            {activeTab==='disc' && (
              <div>
                <p className="text-xs text-slate-400 mb-4 italic">Set T1 and T2 grades for each discipline element.</p>
                <div className="grid grid-cols-2 gap-3">
                  {DISCIPLINE_ITEMS.map(item=>{
                    const g=(overrides[selStu]?.discGrades||{})[item]||'A2';
                    return (
                      <div key={item} className="flex items-center justify-between bg-blue-50 rounded-xl px-4 py-2.5 border border-blue-100">
                        <span className="text-xs text-slate-700 font-medium">{item}</span>
                        <GradeSelect value={g} onChange={v=>setDiscGrade(selStu,item,v)}/>
                      </div>
                    );
                  })}
                </div>
              </div>
            )}

            {/* ATTENDANCE TAB */}
            {activeTab==='att' && (()=>{
              const dbAtt=getAtt(selStu);
              const ovr=overrides[selStu]||{};
              const attP=ovr.attP!==undefined?ovr.attP:dbAtt.p;
              const attT=ovr.attT!==undefined?ovr.attT:dbAtt.t;
              return (
                <div className="space-y-4">
                  <p className="text-xs text-slate-400 italic">Auto-calculated from attendance records. Override if needed.</p>
                  <div className="flex gap-6 items-center bg-blue-50 rounded-xl p-4 border border-blue-100">
                    <div className="text-sm text-slate-500">From records: <strong className="text-blue-700">{dbAtt.p} / {dbAtt.t}</strong></div>
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <label className="block text-xs font-bold text-slate-500 mb-1.5 uppercase tracking-wider">Days Present</label>
                      <input type="number" min="0" value={attP}
                        onChange={e=>setOvr(selStu,{attP:parseInt(e.target.value)||0})}
                        className="w-full p-2.5 bg-blue-50 border border-blue-200 rounded-xl text-sm text-slate-700 focus:ring-2 focus:ring-blue-300 outline-none"/>
                    </div>
                    <div>
                      <label className="block text-xs font-bold text-slate-500 mb-1.5 uppercase tracking-wider">Total Working Days</label>
                      <input type="number" min="0" value={attT}
                        onChange={e=>setOvr(selStu,{attT:parseInt(e.target.value)||0})}
                        className="w-full p-2.5 bg-blue-50 border border-blue-200 rounded-xl text-sm text-slate-700 focus:ring-2 focus:ring-blue-300 outline-none"/>
                    </div>
                  </div>
                  <button onClick={()=>setOvr(selStu,{attP:undefined,attT:undefined})}
                    className="text-xs text-slate-400 hover:text-red-500 transition-colors cursor-pointer border-0 bg-transparent">
                    Reset to auto-calculated
                  </button>
                </div>
              );
            })()}
          </div>
        </div>
      )}

      {/* Generate buttons */}
      {rcCls && (
        <div className="flex gap-4">
          <button onClick={()=>genRC(selStu==='all'?clsStudents:[editStu].filter(Boolean))}
            className="flex items-center gap-2 px-6 py-3 bg-blue-600 text-white rounded-xl font-bold text-sm shadow-lg hover:bg-blue-700 transition-colors border-0 cursor-pointer">
            <span className="material-symbols-outlined text-lg">description</span>
            {selStu==='all'?`Generate All (${clsStudents.length})`:'Generate This Student'}
          </button>
          {selStu!=='all' && (
            <button onClick={()=>genRC(clsStudents)}
              className="flex items-center gap-2 px-6 py-3 bg-slate-100 text-slate-700 rounded-xl font-bold text-sm hover:bg-slate-200 transition-colors border border-slate-200 cursor-pointer">
              <span className="material-symbols-outlined text-lg">group</span>
              Generate Entire Class
            </button>
          )}
        </div>
      )}

      {!rcCls && (
        <div className="flex flex-col items-center justify-center py-16 text-slate-400">
          <span className="material-symbols-outlined text-5xl mb-3 opacity-30">description</span>
          <p className="font-medium">Select a class to begin</p>
        </div>
      )}
    </div>
  );
}
